const data = $input.first().json;
const doc = { ...data.doc };
doc.flags = Array.isArray(doc.flags) ? [...doc.flags] : [];
const errors = [];

if (!doc.file_name) errors.push('file_name is required');

const allowedTypes = ['pdf','png','jpg','jpeg','tiff','tif','docx','doc','txt','heic','xlsx','csv'];
if (doc.file_type && !allowedTypes.includes(doc.file_type.toLowerCase())) {
  errors.push('Unsupported file type: ' + doc.file_type);
}
if (doc.file_size && doc.file_size > 52428800) {
  errors.push('File exceeds 50MB limit');
}
if (!doc.document_text && !doc.file_content_base64) {
  doc.flags.push('no_content_provided');
  doc.flags.push('content_missing_may_need_ocr');
}
if (doc.document_text && doc.document_text.trim().length < 10) {
  doc.flags.push('very_short_text');
}

if (errors.length > 0) {
  doc.validation_passed = false;
  doc.validation_errors = errors;
  doc.processing_status = 'failed';
  doc.downstream_action = 'reject';
} else {
  doc.validation_passed = true;
}

return [{ json: { doc, raw_payload: data.raw_payload } }];

const data = $input.first().json;
const doc = { ...data.doc };
doc.flags = Array.isArray(doc.flags) ? [...doc.flags] : [];

if (doc.document_text && doc.document_text.trim().length > 10) {
  doc.flags.push('text_provided_directly');
  return [{ json: { doc, raw_payload: data.raw_payload } }];
}

if (doc.file_content_base64) {
  try {
    const decoded = Buffer.from(doc.file_content_base64, 'base64').toString('utf-8');
    const printable = decoded.replace(/[\x00-\x08\x0e-\x1f\x7f-\x9f]/g, '');
    const ratio = printable.length / Math.max(decoded.length, 1);
    if (ratio > 0.85 && printable.length > 20) {
      doc.document_text = printable.substring(0, 8000);
      doc.flags.push('text_extracted_from_content');
    } else {
      doc.flags.push('binary_content_ocr_needed');
      doc.document_text = '[Binary content — OCR required]';
    }
  } catch(e) {
    doc.flags.push('text_extraction_failed');
    doc.document_text = '[Text extraction failed]';
  }
} else {
  doc.document_text = '[No content — classification from metadata only]';
  doc.flags.push('metadata_only_classification');
}

return [{ json: { doc, raw_payload: data.raw_payload } }];

const ollamaData = $input.first().json;
const prevData = $('Validation Gate').first().json;
const doc = { ...prevData.doc };
doc.flags = Array.isArray(doc.flags) ? [...doc.flags] : [];

try {
  const extracted = $('Extract Text').first().json;
  if (extracted && extracted.doc) {
    doc.document_text = extracted.doc.document_text || doc.document_text;
    doc.flags = [...new Set([...doc.flags, ...(extracted.doc.flags || [])])];
  }
} catch(e) {}

const rawText = doc.document_text || '';
const searchText = (rawText + ' ' + (doc.file_name || '') + ' ' + (doc.subject || '') + ' ' + (doc.sender || '')).toLowerCase();

const VALID_LABELS = ['invoice','contract','intake_form','referral','receipt','court_document','id_document','tax_document','real_estate','correspondence','unknown'];
const ROUTING_MAP = { invoice:'accounts_payable', contract:'legal_review', intake_form:'client_services', referral:'patient_intake', receipt:'expense_management', court_document:'legal_urgent', id_document:'compliance', tax_document:'finance_team', real_estate:'transactions', correspondence:'general_inbox', unknown:'human_review_queue' };

// ── Step 1: Keyword-based classification (deterministic, instant) ──────
function keywordClassify(t) {
  if (/\b(invoice|inv-|amount due|bill to|invoice number|vendor invoice|billed by|remittance|payable to)\b/.test(t)) return 'invoice';
  if (/\b(patient referral|referring physician|npi:|diagnosis code|diagnosis:|referral to|authorization number|auth-)\b/.test(t)) return 'referral';
  if (/\b(non-disclosure|nda\b|this agreement|shall not disclose|confidential information|governing law|party a|party b)\b/.test(t)) return 'contract';
  if (/\b(receipt|total paid|merchant:|transaction date|payment method:|purchase receipt)\b/.test(t)) return 'receipt';
  if (/\b(intake form|client intake|patient intake|service requested:|reason for visit|chief complaint)\b/.test(t)) return 'intake_form';
  if (/\b(case no|case number|plaintiff|defendant|in the court|motion for|order of|judicial)\b/.test(t)) return 'court_document';
  if (/\b(passport|driver.?s license|state id|license no|document no|date of expiry|issuing authority)\b/.test(t)) return 'id_document';
  if (/\b(w-?2\b|1099-|form 1040|tax return|taxable income|tax year|irs|wages and tips)\b/.test(t)) return 'tax_document';
  if (/\b(purchase agreement|real estate|escrow|closing date|property address|buyer:|seller:|title insurance)\b/.test(t)) return 'real_estate';
  if (/\b(dear |to whom it may concern|sincerely,|memorandum|re: |per our discussion)\b/.test(t)) return 'correspondence';
