  extractedFields = {
    invoice_number: extract(/(?:invoice\s*(?:number|#|no\.?)|INV[-#])\s*([\w-]+)/i, rawText),
    vendor_name: extract(/(?:^|\n)([A-Z][A-Za-z\s]+(?:LLC|Inc\.?|Corp\.?|Co\.?|Ltd\.?))\s*\n/m, rawText),
    invoice_date: extract(/(?:invoice date|date)[:\s]+(\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4}|(?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\.?\s+\d{1,2},?\s+\d{4})/i, rawText),
    due_date: extract(/due\s*(?:date|by|on)[:\s]+(\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4}|(?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\.?\s+\d{1,2},?\s+\d{4})/i, rawText),
    total_amount: extract(/(?:total(?: due| amount)?|amount due|grand total|balance due)[:\s]*\$?([\d,]+\.\d{2})/i, rawText),
    currency: extract(/\b(USD|EUR|GBP|CAD|AUD)\b/, rawText) || 'USD',
    payment_terms: extract(/payment terms[:\s]+([\w\s]+?)(?:\n|$)/i, rawText)
  };
} else if (label === 'referral') {
  extractedFields = {
    patient_name: extract(/patient\s+name\s*:\s*([A-Za-z]+(?:[ \t]+[A-Za-z]+)*)/i, rawText),
    date_of_birth: extract(/(?:date of birth|dob)[:\s]+(\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4})/i, rawText),
    referring_physician: extract(/referring\s*(?:physician|doctor|provider)[:\s]+(?:Dr\.?\s+)?([A-Za-z]+\s+[A-Za-z]+(?:,\s*M\.?D\.?)?)/i, rawText),
    npi: extract(/NPI[:\s#]+([0-9]{10})/i, rawText),
    diagnosis_code: extract(/(?:ICD|diagnosis\s*code)[:\s]+([A-Z]\d{2,3}(?:\.\d+)?)/i, rawText),
    diagnosis_description: extract(/(?:diagnosis|condition|impression)[:\s]+([A-Za-z][\w\s,]+?)(?:\n|$)/i, rawText),
    authorization_number: extract(/(?:auth(?:orization)?\s*(?:number|#|no)[:\s]+)([\w-]+)/i, rawText),
    urgency: extract(/urgency[:\s]+([\w]+)/i, rawText) || 'routine'
  };
} else if (label === 'contract') {
  extractedFields = {
    contract_type: extract(/^(NON-DISCLOSURE AGREEMENT|NDA|SERVICE AGREEMENT|PURCHASE AGREEMENT|CONSULTING AGREEMENT|EMPLOYMENT AGREEMENT|PARTNERSHIP AGREEMENT)/im, rawText),
    effective_date: extract(/(?:effective|entered into|dated?)\s+(?:as of\s+)?([A-Za-z]+\s+\d{1,2},?\s+\d{4}|\d{1,2}[\/-]\d{1,2}[\/-]\d{4})/i, rawText),
    governing_law: extract(/governing\s*law[:\s]+(?:laws? of the State of\s+)?([A-Za-z]+)/i, rawText),
    term: extract(/(\d+)\s+years?\s+(?:from|term|agreement)/i, rawText)
  };
} else if (label === 'receipt') {
  extractedFields = {
    merchant_name: extract(/^([A-Z][\w\s&]+)\s*\n/m, rawText),
    transaction_date: extract(/(?:date|transaction date)[:\s]+(\d{1,2}[\/-]\d{1,2}[\/-]\d{4})/i, rawText),
    total_amount: extract(/(?:total|amount)[:\s]*\$?([\d,]+\.\d{2})/i, rawText),
    currency: extract(/\b(USD|EUR|GBP|CAD|AUD)\b/, rawText) || 'USD',
    payment_method: extract(/(?:paid by|payment method|card type)[:\s]+([\w\s]+?)(?:\n|$)/i, rawText)
  };
} else if (label === 'court_document') {
  extractedFields = {
    case_number: extract(/(?:case\s*(?:no|number|#))[:\s]+([\w-]+)/i, rawText),
    court_name: extract(/(?:in the|before the)?\s*(\w+ court[\w\s]*)(?:\n|$)/i, rawText),
    filing_date: extract(/(?:filed|filing date)[:\s]+(\d{1,2}[\/-]\d{1,2}[\/-]\d{4})/i, rawText),
    document_type: extract(/^(MOTION|ORDER|COMPLAINT|SUMMONS|JUDGMENT|NOTICE|PETITION|SUBPOENA)/im, rawText)
  };
} else if (label === 'tax_document') {
  extractedFields = {
    form_type: extract(/\b(W-?2|1099-?[A-Z]*|1040|1065|1120|990)\b/i, rawText),
    tax_year: extract(/(?:tax year|year)[:\s]+(\d{4})|\b(20\d{2})\b/, rawText),
    taxpayer_name: extract(/(?:employee|taxpayer)[:\s]+([A-Za-z]+\s+[A-Za-z]+)/i, rawText)
  };
} else if (label === 'real_estate') {
  extractedFields = {
    property_address: extract(/(?:property address|premises|located at|property:)[:\s]+([\d][\w\s,\.]+?)(?:\n|$)/i, rawText),
    purchase_price: extract(/(?:purchase price|sale price|agreed price)[:\s]*\$?([\d,]+(?:\.\d{2})?)/i, rawText),
    closing_date: extract(/(?:closing date|close of escrow)[:\s]+([A-Za-z]+\s+\d{1,2},?\s+\d{4}|\d{1,2}[\/-]\d{1,2}[\/-]\d{4})/i, rawText)
  };
} else if (label === 'id_document') {
  extractedFields = {
    id_type: extract(/\b(PASSPORT|DRIVER.?S LICENSE|STATE ID|NATIONAL ID)\b/i, rawText),
    id_number: extract(/(?:license no|id no|document no|number)[:\s]+([A-Z0-9]+)/i, rawText),
    full_name: extract(/(?:name|holder)[:\s]+([A-Za-z]+\s+[A-Za-z]+)/i, rawText),
    expiry_date: extract(/(?:expiry|expires|valid through|valid until)[:\s]+(\d{1,2}[\/-]\d{1,2}[\/-]\d{4})/i, rawText)
  };
} else if (label === 'correspondence') {
  extractedFields = {
    document_date: extract(/^((?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\.?\s+\d{1,2},?\s+\d{4}|\d{1,2}[\/-]\d{1,2}[\/-]\d{4})/im, rawText),
    subject: doc.subject || extract(/(?:re|subject)[:\s]+([^\n]+)/i, rawText)
  };
} else if (label === 'intake_form') {
  extractedFields = {
    client_name: extract(/(?:name|client name|patient name)[:\s]+([A-Za-z]+\s+[A-Za-z]+)/i, rawText),
    contact_email: extract(/([\w.+-]+@[\w-]+\.[\w.]+)/, rawText),
    contact_phone: extract(/(\(?\d{3}\)?[\s.-]\d{3}[\s.-]\d{4})/, rawText),
    service_requested: extract(/(?:service requested|reason for visit)[:\s]+([^\n]+)/i, rawText)
  };
}

// Remove null values from extracted fields
extractedFields = Object.fromEntries(Object.entries(extractedFields).filter(([k,v]) => v !== null && v !== undefined && v !== ''));

// ── Step 5: Enforce confidence thresholds ─────────────────────────────
let downstreamAction, reviewRequired = false;
if (label === 'unknown' || confidence < 0.50) {
  downstreamAction = 'human_review'; reviewRequired = true; doc.flags.push('low_confidence_review');
} else if (confidence < 0.80) {
  downstreamAction = 'human_review'; reviewRequired = true; doc.flags.push('moderate_confidence_review');
} else {
  downstreamAction = 'auto_process';
}
if (label === 'court_document') { downstreamAction = 'escalate'; reviewRequired = true; doc.flags.push('auto_escalated_court_doc'); }

const year = new Date().getFullYear();
const month = String(new Date().getMonth() + 1).padStart(2, '0');
const routingDestination = ROUTING_MAP[label] || 'human_review_queue';
const filingTarget = label !== 'unknown' ? label + '/' + year + '/' + month : 'unclassified/pending';

doc.classification_label = label;
doc.confidence_score = confidence;
doc.routing_destination = routingDestination;
doc.filing_target = filingTarget;
doc.downstream_action = downstreamAction;
doc.review_required = reviewRequired;
doc.extracted_fields = extractedFields;
doc.classification_result = { label, confidence, routing_destination: routingDestination, filing_target: filingTarget, keyword_match: kwLabel, ai_label: aiLabel, ai_success: aiSuccess };
doc.processed_at = new Date().toISOString();

return [{ json: { doc, raw_payload: prevData.raw_payload } }];

const doc = $input.first().json.doc;
const raw = $input.first().json.raw_payload;
// High-confidence auto-process: file it, mark ready for downstream system
const year = new Date().getFullYear();
const month = String(new Date().getMonth() + 1).padStart(2, '0');
const filedPath = (doc.filing_target || doc.classification_label + '/general') + '/' + year + '/' + month;
return [{ json: {
  doc: { ...doc, processing_status: 'success', filed_path: filedPath },
  raw_payload: raw,
  action_taken: 'auto_processed',
  filed_to: filedPath
} }];

